import { Panel as PanelRoot, type PanelProps, panelVariants } from "./panel";
import { PanelHeader, type PanelHeaderProps, panelHeaderVariants } from "./panel-header";
import { PanelContent, type PanelContentProps, panelContentVariants } from "./panel-content";
import { PanelFooter, type PanelFooterProps } from "./panel-footer";

const Panel = Object.assign(PanelRoot, {
  Header: PanelHeader,
  Content: PanelContent,
  Footer: PanelFooter,
});

export { Panel, type PanelProps, panelVariants };
export { PanelHeader, type PanelHeaderProps, panelHeaderVariants };
export { PanelContent, type PanelContentProps, panelContentVariants };
export { PanelFooter, type PanelFooterProps };

"use client";

import type { ComponentPropsWithRef } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";

export const panelVariants = cva("relative bg-background", {
  variants: {
    variant: {
      default: "border border-border shadow-2xl",
      borderless: "",
    },
  },
  defaultVariants: { variant: "default" },
});

type PanelTag = "div" | "article" | "section" | "aside";

export type PanelProps = ComponentPropsWithRef<"div"> &
  VariantProps<typeof panelVariants> & {
    as?: PanelTag;
  };

export function Panel({ className, variant, as: Tag = "div", ...props }: PanelProps) {
  return <Tag data-slot="panel" className={cn(panelVariants({ variant }), className)} {...props} />;
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";

export const panelHeaderVariants = cva("", {
  variants: {
    variant: {
      default: "flex items-center justify-between border-b border-border bg-secondary/30 px-6 py-4 text-sm font-semibold text-foreground",
      terminal:
        "flex items-center justify-between bg-secondary text-muted-foreground text-xs px-3 py-1 border-b border-border font-bold uppercase tracking-wider",
      subtle:
        "bg-secondary/30 text-muted-foreground text-xs p-2 border-b border-border uppercase tracking-widest text-center",
    },
  },
  defaultVariants: { variant: "default" },
});

export type PanelHeaderProps = ComponentPropsWithRef<"div"> &
  VariantProps<typeof panelHeaderVariants>;

export function PanelHeader({ className, variant, ...props }: PanelHeaderProps) {
  return <div data-slot="panel-header" className={cn(panelHeaderVariants({ variant }), className)} {...props} />;
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";

export const panelContentVariants = cva("p-4 text-sm", {
  variants: {
    spacing: {
      none: "",
      sm: "space-y-2",
      md: "space-y-4",
    },
  },
  defaultVariants: { spacing: "md" },
});

export type PanelContentProps = ComponentPropsWithRef<"div"> & VariantProps<typeof panelContentVariants>;

export function PanelContent({ className, spacing, ...props }: PanelContentProps) {
  return <div data-slot="panel-content" className={cn(panelContentVariants({ spacing }), className)} {...props} />;
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type PanelFooterProps = ComponentPropsWithRef<"div">;

export function PanelFooter({ className, ...props }: PanelFooterProps) {
  return <div data-slot="panel-footer" className={cn("border-t border-border bg-secondary/30 px-4 py-3 text-sm", className)} {...props} />;
}
